import React from "react";
import { Link } from "react-router-dom"; // Adding active navigation tracking
import PersonOutlinedIcon from "@mui/icons-material/PersonOutlined";
import SettingsOutlinedIcon from "@mui/icons-material/SettingsOutlined";
import ExitToAppOutlinedIcon from "@mui/icons-material/ExitToAppOutlined";

const UserMenu = () => {
  const handleLogout = (e) => {
    e.stopPropagation(); // Prevents clicking logout from misfiring navbar state closures
    console.log("Clearing active sessions...");
    alert("Logged out successfully! Redirecting...");
    window.location.href = "/"; // Reboots layout context state cleanly back to splash routes
  };

  return (
    <div className="user-dropdown-menu" onClick={(e) => e.stopPropagation()}>
      <div className="user-menu-header">
        <h6>User Name</h6>
        <p>student_club@zerodha.com</p>
      </div>
      <hr className="menu-divider" />

      <ul className="menu-links-list">
        {/* Profile Navigation Action */}
        <Link
          to="/profile"
          style={{ textDecoration: "none", color: "inherit" }}
        >
          <li>
            <PersonOutlinedIcon className="menu-icon" />
            <span>My Profile</span>
          </li>
        </Link>

        {/* Console / Settings Action */}
        <Link
          to="/settings"
          style={{ textDecoration: "none", color: "inherit" }}
        >
          <li>
            <SettingsOutlinedIcon className="menu-icon" />
            <span>Settings</span>
          </li>
        </Link>

        {/* Clear session Logout Action Row */}
        <li className="logout-item" onClick={handleLogout}>
          <ExitToAppOutlinedIcon className="menu-icon logout-icon" />
          <span>Log out</span>
        </li>
      </ul>
    </div>
  );
};

export default UserMenu;
